import React, { useState, useEffect } from 'react';
import { aiAPI } from '../services/api';
import { toast } from 'react-toastify';
const InsightsPage = () => {
  const [pred, setPred] = useState(null);
  const [advice, setAdvice] = useState(null);
  const [anom, setAnom] = useState(null);
  const [loading, setLoading] = useState(true);
  useEffect(()=>{load();},[]);
  const load = async () => { try{const[p,a,n]=await Promise.all([aiAPI.getPredictions(),aiAPI.getBudgetAdvice(),aiAPI.getAnomalies()]);setPred(p.data);setAdvice(a.data);setAnom(n.data);}catch{toast.error('Failed');}finally{setLoading(false);} };
  if(loading) return <div style={{display:'flex',justifyContent:'center',alignItems:'center',height:'80vh'}}><p>AI analyzing...</p></div>;
  return <div style={{padding:24,maxWidth:1200,margin:'0 auto'}}><h1 style={{fontSize:28,fontWeight:'bold',marginBottom:32}}>AI Insights</h1>
    <div className='glass' style={{padding:24,marginBottom:24}}><h2 style={{marginBottom:16}}>Predictions</h2>
      {pred?.predicted_spending>0?<div style={{padding:16,background:'rgba(139,92,246,0.1)',borderRadius:12,textAlign:'center'}}><p style={{color:'#9ca3af'}}>Next Month</p><p style={{fontSize:28,fontWeight:'bold',color:'#a855f7'}}></p></div>:<p style={{color:'#6b7280'}}>{pred?.message||'Add more data'}</p>}
    </div>
    <div className='glass' style={{padding:24,marginBottom:24}}><h2 style={{marginBottom:16}}>Budget Advice</h2>
      <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fit,minmax(300px,1fr))',gap:16}}>
        {advice?.advice?.map((a,i)=><div key={i} style={{padding:16,background:'rgba(99,102,241,0.1)',borderRadius:12}}><h3>{a.title}</h3><p style={{fontSize:14,color:'#d1d5db'}}>{a.message}</p></div>)}
      </div></div>
    <div className='glass' style={{padding:24}}><h2 style={{marginBottom:16}}>Anomalies</h2>
      {anom?.anomalies?.length>0?anom.anomalies.map((a,i)=><div key={i} style={{padding:16,background:'rgba(239,68,68,0.1)',borderRadius:12,marginBottom:12,display:'flex',justifyContent:'space-between'}}><div><p style={{fontWeight:600}}>{a.transaction.description}</p><p style={{fontSize:12,color:'#9ca3af'}}>{a.reasons.join(', ')}</p></div><p style={{fontSize:18,fontWeight:'bold',color:'#ef4444'}}></p></div>):<p style={{color:'#6b7280',textAlign:'center',padding:32}}>No anomalies!</p>}
    </div></div>;
};
export default InsightsPage;
